import { dateToStr, dateToHours } from "../../utils/dates";
import { updateAllLoopIndexes } from "../../utils/loopIndexes";
import { IconR, IconZ } from "../Simple/Image";
import "./Summary.css";

import React, { useState, useEffect } from "react";
//const React = window.React;
//const { useState, useEffect } = React;

const Form = window.ReactBootstrap.Form;

export const Summary = ({ data }) => {
  const [isStcHidden, setIsStcHidden] = useState(false);
  const [isFlatHidden, setIsFlatHidden] = useState(false);
  const [isDistanceDisplayed, setIsDistanceDisplayed] = useState(false);
  const [distValue, setDistValue] = useState("0.3");

  useEffect(() => {
    updateAllLoopIndexes();
  }, []);

  /**
   * Display STC
   */
  const numSTCs = data.items.filter((item) => item.sold_let).length;
  const numStcStr = `Exclude the ${numSTCs} STCs`;
  const OnStcCheckChanged = (event) => {
    setIsStcHidden(event.target.checked);
    document.querySelectorAll(".x-card-stc").forEach((elem) => {
      if (event.target.checked) {
        elem.classList.add("x-hidden-stc");
      } else {
        elem.classList.remove("x-hidden-stc");
      }
    });
    updateAllLoopIndexes();
  };

  /**
   * Display Flat
   */
  const numFlats = data.items.filter((item) => item.property_group_icon === "🏢").length;
  const numFlatsStr = `Exclude the ${numFlats} flats`;
  const OnFlatCheckChanged = (event) => {
    setIsFlatHidden(event.target.checked);
    document.querySelectorAll("[data-isflat='true']").forEach((elem) => {
      if (event.target.checked) {
        elem.classList.add("x-hidden-flat");
      } else {
        elem.classList.remove("x-hidden-flat");
      }
    });
    updateAllLoopIndexes();
  };

  /**
   * Display Distance
   */
  const applyDistON = () => {
    if (isDistanceDisplayed) return; // already in correct state
    setIsDistanceDisplayed(true);
    const maxMiles = parseFloat(document.querySelector("#distance-miles").value);
    document.querySelectorAll(".x-card").forEach((elem) => {
      if (elem.dataset.miles > maxMiles) {
        elem.classList.add("x-hidden-distance");
      } else {
        elem.classList.remove("x-hidden-distance");
      }
    });
    updateAllLoopIndexes();
  };
  const applyDistOFF = () => {
    if (!isDistanceDisplayed) return; // already in correct state
    setIsDistanceDisplayed(false);
    document.querySelectorAll(".x-card").forEach((elem) => {
      elem.classList.remove("x-hidden-distance");
    });
    updateAllLoopIndexes();
  };
  const onChangeDist = (value) => {
    setDistValue(value);
    applyDistOFF();
  };
  const onKeyDown = (event) => {
    if (event.key === "Enter") {
      applyDistON();
    } else {
      applyDistOFF();
    }
  };
  const OnDistanceCheckChanged = (event) => {
    if (event.target.checked) {
      applyDistON();
    } else {
      applyDistOFF();
    }
  };

  return (
    <>
      <h1 style={{ textTransform: "uppercase" }}>{data.region}</h1>
      <h5>{data.title}</h5>
      <UpdatedOn data={data} />
      <AllSearches searches={data.searches} />
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          label={numStcStr}
          id="check-1"
          onChange={OnStcCheckChanged}
          checked={isStcHidden}
        />
      </Form>
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          label={numFlatsStr}
          id="check-2"
          onChange={OnFlatCheckChanged}
          checked={isFlatHidden}
        />
      </Form>
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          id="check-3"
          onChange={OnDistanceCheckChanged}
          checked={isDistanceDisplayed}
        />
        <p>Exclude further than</p>
        <Form.Control
          value={distValue}
          aria-label="Distance"
          aria-describedby="distance-entry"
          id="distance-miles"
          onChange={(e) => onChangeDist(e.target.value)}
          style={{
            maxWidth: "3rem",
            height: "1.5rem",
            margin: "0 0.5rem",
            textAlign: "center",
          }}
          onKeyDown={onKeyDown}
        />
        <p>miles</p>
      </Form>
    </>
  );
};

const UpdatedOn = ({ data }) => {
  return (
    <p>
      Updated{" "}
      <span
        id="x-updated-relative"
        className="x-date-relative"
        data-convert="hours"
        data-date={data.updated_on}
      >
        {dateToHours(data.updated_on)}
      </span>{" "}
      ago
      <br />
      (on <span>{dateToStr(data.updated_on)}</span>
      )
      <br />
      next check starts in:{" "}
      <span
        id="x-nexton-relative"
        className="x-date-relative"
        data-convert="hours-negative"
        data-date={data.next_on}
      >
        {dateToHours(data.next_on, true)}
      </span>
    </p>
  );
};

const AllSearches = ({ searches }) => {
  return (
    <p>
      Results based on <IconR style={{ verticalAlign: "baseline" }} /> searches:
      <br />
      {searches &&
        searches
          .map((search, index) => <SearchItem key={index} search={search} />)
          .reduce((prev, curr) => [prev, " ◆ ", curr])}
    </p>
  );
};

const SearchItem = ({ search }) => {
  return (
    <span className="x-nowrap">
      <strong>{search.name}</strong>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_r}>
        <IconR isLink={true} style={{ verticalAlign: "sub" }} />
      </a>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_z}>
        <IconZ isLink={true} style={{ verticalAlign: "sub" }} />
      </a>
    </span>
  );
};

export default Summary;
